// ===================================================
// BUILD GROK-3 REQUEST FROM INCOMING WEBHOOK PAYLOAD
// AgilityServ Quantum Pipeline — Website Signal Node
// ===================================================

const raw = $input.item.json;
// Support both { body: {...} } and flat payloads
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;

// --- Extract all indicator fields with safe defaults ---
const ticker      = (body.ticker       || 'UNKNOWN').toString().toUpperCase();
const price       = body.price         ?? body.close ?? null;
const change      = body.change        ?? 0;
const changePct   = body.changePercent ?? body.changePct ?? 0;
const volume      = body.volume        ?? null;
const rsi         = body.rsi14         ?? body.rsi   ?? null;
const macdLine    = body.macdLine      ?? body.macd  ?? null;
const macdSig     = body.macdSignal    ?? null;
const macdHist    = body.macdHistogram ?? body.macdHist ?? null;
const ema20       = body.ema20         ?? null;
const ema50       = body.ema50         ?? null;
const sma200      = body.sma200        ?? null;
const atr         = body.atr14         ?? body.atr   ?? null;
const bbUpper     = body.bollingerUpper ?? body.bbUpper ?? null;
const bbLower     = body.bollingerLower ?? body.bbLower ?? null;
const bbMid       = body.bollingerMid  ?? body.bbMid  ?? null;
const vwap        = body.vwap          ?? null;

const fmt = (v, decimals = 2) =>
  v !== null && v !== undefined ? Number(v).toFixed(decimals) : 'N/A';

const sign = (v) => (Number(v) >= 0 ? '+' : '');

// --- Build the clean user message sent to Grok ---
const userMessage =
`Analyze ${ticker} and generate a trading signal.

== MARKET DATA ==
Ticker:           ${ticker}
Price:            $${fmt(price)} (${sign(change)}${fmt(change)} / ${sign(changePct)}${fmt(changePct)}%)
Volume:           ${volume !== null ? Number(volume).toLocaleString() : 'N/A'}

== TECHNICAL INDICATORS ==
RSI(14):          ${fmt(rsi)}
MACD Line:        ${fmt(macdLine)}
MACD Signal:      ${fmt(macdSig)}
MACD Histogram:   ${fmt(macdHist)}
EMA(20):          $${fmt(ema20)}
EMA(50):          $${fmt(ema50)}
SMA(200):         $${fmt(sma200)}
ATR(14):          ${fmt(atr)}
Bollinger Upper:  $${fmt(bbUpper)}
Bollinger Mid:    $${fmt(bbMid)}
Bollinger Lower:  $${fmt(bbLower)}
VWAP:             $${fmt(vwap)}

Return ONLY the JSON object — no markdown, no explanation text outside the JSON.`;

// --- System prompt: AgilityServ Quantum Pipeline ---
const systemPrompt =
`You are the core signal engine of AgilityServ's institutional-grade quantum trading pipeline.
You analyze real-time price and technical indicator data to generate high-conviction, risk-adjusted trading signals.

Your analysis framework — evaluate all six layers in order:

1. MOMENTUM LAYER
   - RSI(14): Oversold < 35 (potential BUY setup), Overbought > 65 (potential SELL setup)
   - RSI 35-65: neutral zone — direction depends on other factors
   - MACD histogram positive and expanding = bullish momentum; negative and expanding = bearish
   - MACD Line crossing Signal Line: golden cross = bullish, death cross = bearish
   - If RSI < 25 or RSI > 75: extreme — DO NOT enter, return STAND ASIDE regardless

2. TREND ALIGNMENT
   - Price vs EMA20: above = short-term bullish, below = short-term bearish
   - Price vs EMA50: above = medium-term bullish, below = medium-term bearish
   - Price vs SMA200: above = long-term uptrend, below = long-term downtrend
   - Golden cross (EMA20 > EMA50 > SMA200 & price above all): strongest BUY context
   - Death cross (EMA20 < EMA50 < SMA200 & price below all): strongest SELL context
   - Mixed alignment reduces conviction — lower VC Gate score

3. VOLATILITY & STRUCTURE
   - ATR: defines stop-loss sizing (stop = price ± 1.5× ATR)
   - Bollinger Band: price near upper band = overbought warning; near lower band = oversold warning
   - Price inside Bollinger Bands, trending toward upper from mid = bullish momentum context
   - Bollinger squeeze (bands contracting) = breakout pending — be cautious

4. INSTITUTIONAL ANCHOR (VWAP)
   - Price above VWAP = institutions net buyers — supports BUY signals
   - Price below VWAP = institutions net sellers — supports SELL signals
   - VWAP confluence with MA alignment amplifies conviction

5. VC GATE SCORING (0–10, institutional conviction gating)
   - Each aligned indicator adds to the gate score:
     +2: RSI in correct zone (not extreme)
     +2: MACD aligned with direction
     +2: All 3 MAs aligned (EMA20 > EMA50 > SMA200 for BUY)
     +2: Price vs VWAP confirms direction
     +2: Bollinger position confirms direction
   - VC Gate Score ≥ 7: emit BUY or SELL signal
   - VC Gate Score 5–6: weak setup — emit STAND ASIDE
   - VC Gate Score < 5: conflicting signals — emit STAND ASIDE

6. QUANTUM EDGE SCORE (0–100)
   - Proprietary confluence score: measures signal quality, timing, and risk/reward
   - High edge (> 70): multiple indicators in perfect alignment
   - Low edge (< 40): choppy or conflicting environment

Signal Construction Rules:
- BUY: VC Gate ≥ 7, bullish indicators majority, RSI 40–62, positive MACD histogram, price above VWAP
- SELL: VC Gate ≥ 7, bearish indicators majority, RSI 38–60, negative MACD histogram, price below VWAP
- STAND ASIDE: any extreme RSI (< 25 or > 75), VC Gate < 7, or 3+ contradicting signals
- confidence: 0–100. Never exceed 88 (no certainty in markets). Scale with VC Gate score and confluence.
- Trade Plan: entry = current price. target1 = entry ± 1.5× ATR. target2 = entry ± 3× ATR. stop = entry ∓ 1.5× ATR.

Respond with ONLY this JSON structure. No markdown. No text before or after:
{
  "signal": "BUY" | "SELL" | "STAND ASIDE",
  "confidence": <integer 0-100>,
  "correlationScore": <integer 0-100>,
  "vcGateScore": <number 0-10 with one decimal>,
  "quantumEdgeScore": <integer 0-100>,
  "reasons": ["<concise reason 1>", "<concise reason 2>", "<concise reason 3>"],
  "tradePlan": {
    "entry": <number>,
    "target1": <number>,
    "target2": <number>,
    "stop": <number>,
    "riskReward": "1:<ratio to one decimal>",
    "timeframe": "intraday" | "swing" | "position"
  },
  "analyzedBy": "Grok-3"
}`;

// --- Assemble the final Grok API request body ---
const requestBody = {
  model: 'grok-3',
  messages: [
    { role: 'system',  content: systemPrompt },
    { role: 'user',    content: userMessage  }
  ],
  temperature: 0.3,
  max_tokens: 900
};

return [{
  json: {
    requestBody,
    ticker,
    price
  }
}];

// ============================================
// PARSE GROK-3 RESPONSE → FRONTEND-READY JSON
// ============================================
try {
  const grokResp = $input.item.json;

  // Extract raw text from the choices array
  const raw = grokResp?.choices?.[0]?.message?.content || '';

  // Strip markdown code fences if Grok wrapped its response
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const parsed = JSON.parse(cleaned);

  // Validate signal enum
  const validSignals = ['BUY', 'SELL', 'STAND ASIDE'];
  const signal = validSignals.includes(parsed.signal) ? parsed.signal : 'STAND ASIDE';

  // Clamp numeric fields
  const clamp = (v, lo, hi) => {
    const n = Number(v);
    return isNaN(n) ? lo : Math.min(hi, Math.max(lo, n));
  };

  const result = {
    signal,
    confidence:        clamp(parsed.confidence,        0, 100),
    correlationScore:  clamp(parsed.correlationScore,  0, 100),
    vcGateScore:       clamp(parsed.vcGateScore,        0,  10),
    quantumEdgeScore:  clamp(parsed.quantumEdgeScore,   0, 100),
    reasons:           Array.isArray(parsed.reasons) ? parsed.reasons.slice(0, 5) : ['Grok-3 analysis complete'],
    tradePlan:         parsed.tradePlan   || {},
    analyzedBy:        'Grok-3',
    timestamp:         new Date().toISOString(),
    _status:           'ok'
  };

  return [{ json: result }];

} catch (err) {
  // Safe parse-error fallback — still returns valid shape for frontend
  return [{
    json: {
      signal:           'STAND ASIDE',
      confidence:        0,
      correlationScore:  0,
      vcGateScore:       0,
      quantumEdgeScore:  0,
      reasons:           ['Grok-3 response could not be parsed — safe default applied'],
      tradePlan:         {},
      analyzedBy:        'Grok-3',
      timestamp:         new Date().toISOString(),
      _status:           'parse_error',
      _error:            err.message
    }
  }];
}

// ================================================
// API ERROR HANDLER — returns safe STAND ASIDE
// so the frontend can trigger clientSideFallback()
// ================================================
const errData = $input.item.json?.error || {};
const msg = errData?.message || errData?.description || 'Grok-3 API unavailable';

return [{
  json: {
    signal:           'STAND ASIDE',
    confidence:        0,
    correlationScore:  0,
    vcGateScore:       0,
    quantumEdgeScore:  0,
    reasons: [
      'Grok-3 API temporarily unavailable',
      'Client-side fallback mode activated',
      msg.toString().substring(0, 120)
    ],
    tradePlan:    {},
    analyzedBy:   'Grok-3 (offline)',
    timestamp:    new Date().toISOString(),
    _status:      'api_error'
  }
}];
